      : [];

const messageText = String(normalized.message_text || normalized.text || normalized.message || '').trim();
const lower = messageText.toLowerCase();

function hasCommercialOrOperationalIntent(text) {
  const value = String(text || '');
  return /\b(service|services|offer|offers|package|packages|price|pricing|cost|quote|proposal|budget|website|site|landing|shop|store|ecommerce|build|automation|automate|ai|bot|chatbot|instagram|telegram|crm|lead|leads|sales|funnel|payment|payments|marketplace|content|support|operations|workflow|process|audit|consult|problem|business|company|customer|client|booking|order|integration|api|dm|direct message|reply|inbox)\b/i.test(value)
    || /услуг|сервис|предлож|пакет|цен|прайс|стоим|бюджет|сайт|лендинг|магазин|автоматизац|бот|чат.?бот|инстаграм|телеграм|crm|срм|лид|продаж|воронк|оплат|маркетплейс|контент|поддержк|процесс|бизнес|компан|клиент|заявк|заказ|интеграц|api|апи|директ|сообщен|ответ/i.test(value)
    || /自动|自動|机器人|機器人|客服|私信|消息|报价|報價|价格|價格|网站|網站|销售|銷售|客户|客戶|线索|線索|支付|流程|业务|業務|集成/i.test(value)
    || /tự động|tu dong|bot|chatbot|instagram|telegram|crm|khách hàng|khach hang|báo giá|bao gia|giá|gia|website|trang web|lead|bán hàng|ban hang|thanh toán|thanh toan|tích hợp|tich hop/i.test(value);
}

function isConversationStarter(text) {
  const value = String(text || '').trim();
  return /^(?:hi|hello|hey|yo)(?:[\s!.?,;:]+|$)/i.test(value)
    || /^good\s*(?:morning|afternoon|evening)(?:[\s!.?,;:]+|$)/i.test(value)
    || /^(?:привет|здравствуй|здравствуйте|добрый|доброе)(?:[\s!.?,;:]+|$)/iu.test(value)
    || /^(?:hola|bonjour|hallo|ciao|xin chao|chao|chào)(?:[\s!.?,;:]+|$)/iu.test(value)
    || /^(?:你好|您好)(?:[\s!.?,;:，。！？、]+|$)/u.test(value);
}
function hasHardEscalationSignal(text) {
  const value = String(text || '');
  const explicitEnglishHandoff = /\b(human|operator|real person|live agent|escalate|handover|transfer me|connect me|talk to (?:a )?(?:human|person|agent|operator|manager))\b/i.test(value);
  const sensitiveEnglish = /\b(complaint|refund|chargeback|legal|lawyer|lawsuit|contract dispute|angry|urgent|emergency|data deletion|gdpr|privacy request|security incident|account access|password|billing dispute)\b/i.test(value);
  const explicitRussianHandoff = /(?:подключ(?:и|ите)?|позови(?:те)?|дай(?:те)?|нуж(?:ен|на)|хочу|перевед(?:и|ите)|соедин(?:и|ите)|передай(?:те)?|передать|переключи(?:те)?).{0,50}(?:оператор|человек|менеджер|специалист|живой|живого)|(?:оператор|человек|менеджер|специалист).{0,30}(?:позвонит|ответит|свяжется|нужен|нужна)/iu.test(value);
  const sensitiveRussian = /жалоб|возврат|чарджбек|юрист|суд|договор.*спор|срочно|экстренно|удал.*данн|персональн.*данн|доступ.*аккаунт|парол|спор.*оплат/iu.test(value);
  const explicitChineseHandoff = /转人工|轉人工|人工客服|真人客服|找客服|人工服务|人工服務/.test(value);
  const sensitiveChinese = /投诉|投訴|退款|紧急|緊急|法律|律师|律師|隐私|隱私|删除数据|刪除資料|安全|密码|密碼/.test(value);
  const explicitVietnameseHandoff = /(?:gặp|gap|nói chuyện|noi chuyen|chuyển|chuyen).{0,40}(?:nhân viên|nhan vien|người thật|nguoi that|tư vấn viên|tu van vien|hỗ trợ viên|ho tro vien)/i.test(value);
  const sensitiveVietnamese = /khiếu nại|khieu nai|hoàn tiền|hoan tien|khẩn cấp|khan cap|pháp lý|phap ly|riêng tư|rieng tu|xóa dữ liệu|xoa du lieu|bảo mật|bao mat|mật khẩu|mat khau/i.test(value);

  return explicitEnglishHandoff || sensitiveEnglish || explicitRussianHandoff || sensitiveRussian || explicitChineseHandoff || sensitiveChinese || explicitVietnameseHandoff || sensitiveVietnamese;
}

function isOffTopicMessage(text) {
  const value = String(text || '');
  if (!value.trim()) return false;
  if (isConversationStarter(value) || hasCommercialOrOperationalIntent(value)) return false;
  return /\b(weather|forecast|temperature|rain|snow|news|sports|football|basketball|movie|recipe|joke|crypto price|bitcoin price|stock price|time now|date today)\b/i.test(value)
    || /погод|прогноз|температур|новост|спорт|футбол|баскетбол|фильм|рецепт|анекдот|шутк|курс биткоин|биткоин|акци[яи]|сколько времени|дата/i.test(value)
    || /天气|天氣|新闻|新聞|体育|體育|电影|電影|菜谱|菜譜|笑话|笑話|比特币|比特幣|股票|几点|幾點/i.test(value)
    || /thời tiết|thoi tiet|tin tức|tin tuc|thể thao|the thao|phim|công thức|cong thuc|truyện cười|truyen cuoi|bitcoin|chứng khoán|chung khoan/i.test(value);
}

const questionLike = /\?|что|как|где|когда|почему|сколько|какой|какая|можно|нужно|how|what|where|when|why|which|can|could|should|多少|怎么|怎麼|什么|什麼|可以|bao nhiêu|bao nhieu|làm sao|lam sao|cái gì|cai gi/i.test(messageText);
const commercialIntent = hasCommercialOrOperationalIntent(messageText);
const conversationStarter = isConversationStarter(messageText);
const hardHandoff = hasHardEscalationSignal(messageText);
const offTopic = isOffTopicMessage(messageText);

let intent = 'ask';
let intentConfidence = 0.76;
let intentReason = 'meaning_first_sales_default';

if (hardHandoff) {
  intent = 'human_handoff';
  intentConfidence = 0.99;
  intentReason = 'explicit_or_sensitive_handoff_signal';
} else if (offTopic && !commercialIntent && !conversationStarter) {
  intent = 'ask';
  intentConfidence = 0.68;
  intentReason = 'ambiguous_or_off_topic_discovery';
} else if (commercialIntent || conversationStarter || questionLike || messageText.length > 12) {
  intent = 'ask';
  intentConfidence = commercialIntent ? 0.94 : questionLike ? 0.88 : 0.78;
  intentReason = commercialIntent ? 'commercial_or_operational_intent' : questionLike ? 'question_like_message' : 'conversation_start_or_context_needed';
}

const recentContext = Array.isArray(threadRows)
  ? threadRows
      .filter((row) => row && typeof row === 'object')
      .slice(0, 4)
      .map((row) => ({
        role: row.role,
        intent: row.intent || null,
        content: row.content,
        confidence: row.confidence,
      }))
  : [];

return [{
  json: {
    ...normalized,
    message_text: messageText,
    tenant_settings: tenantSettings,
    tenant_style: tenantSettings.response_style || 'concise, practical, and polite',
    thread_context_rows: threadRows,
    thread_context_preview: recentContext,
    intent,
    intent_confidence: Number(intentConfidence.toFixed(2)),
    intent_source: intentReason,
    classified_at: new Date().toISOString(),
  },
}];

const source = $node['Classify Message Intent'].json || {};
const payload = $json || {};
const data = Array.isArray(payload.data) ? payload.data : [];
const embedding = data[0]?.embedding;

if (!Array.isArray(embedding) || embedding.length === 0) {
  throw new Error('No embedding returned by OpenAI.');
}

const fallbackModel = 'text-embedding-3-small';
const sourceModel = source.openai_embedding_model || source.tenant_settings?.embedding_model || source.tenant_settings?.openai_embedding_model;
const candidateModel = data[0]?.model || sourceModel || fallbackModel;

return [{
  json: {
    ...source,
    embedding,
    openai_embedding_model: candidateModel,
    openai_embedding_usage: data[0]?.usage || payload.usage || {},
    ask_stage: 'embedded',
    normalized_at: new Date().toISOString(),
  }
}];

