const hasUsefulContext = docs.length > 0 && retrievalSimilarity >= Math.max(0.05, minSimilarity - 0.15);
const semanticFallbackUsed = !hardHandoff && (!hasUsefulContext || (!businessContextSignal && retrievalSimilarity < minSimilarity));

let decisionReason = 'answerable_confidence';
let escalateByConfidence = false;
if (hardHandoff) {
  decisionReason = 'explicit_or_sensitive_handoff_request';
  escalateByConfidence = true;
} else if (docs.length === 0 && (commercialIntent || conversationStarter)) {
  decisionReason = 'semantic_sales_discovery_fallback_no_rag_match';
} else if (docs.length === 0) {
  decisionReason = 'topic_guardrail_fallback_no_rag_match';
} else if (businessContextSignal) {
  decisionReason = 'business_context_answer';
} else if (retrievalSimilarity < minSimilarity) {
  decisionReason = 'weak_context_answer_with_guardrail';
}

const retrievedContext = docs
  .map((row, index) => {
    const sourceLabel = row.source_key || row.source_type || row.id || ('source_' + (index + 1));
    const similarity = Number.isFinite(row.similarity) ? row.similarity.toFixed(3) : '0.000';
    return 'Source ' + (index + 1) + ': ' + sourceLabel + ' (similarity ' + similarity + ')\n' + row.chunk_text;
  })
  .join('\n\n---\n\n');

const semanticFallbackContext = [
  'Meaning-first fallback for inbound commercial conversations when retrieved Supabase context is weak, missing, or not directly matched.',
  publicPriceContext,
  'Primary goal: behave like a capable sales/discovery assistant, not a rigid FAQ bot. Understand the customer intent across any language and keep the conversation moving toward a qualified next step.',
  'Greeting rule: for simple greetings or conversation starters, do not answer generically. Briefly position the company around AI automation, sales/CRM workflows, Instagram/Telegram bots, websites/funnels, and lead handling, then ask which area the customer wants to improve first.',
