async function loadRecentThreadHistory(source) {
  const baseRaw = String($env.SUPABASE_REST_URL || (($env.SUPABASE_URL || '').replace(/\/$/, '') + '/rest/v1'));
  const key = String($env.SUPABASE_SECRET_KEY || $env.SUPABASE_SERVICE_ROLE_KEY || $env.SUPABASE_ANON_KEY || '');
  if (!baseRaw || baseRaw === '/rest/v1' || !key || typeof fetch !== 'function') {
    return { text: '', rows: [], loaded: false, reason: 'supabase_env_or_fetch_unavailable' };
  }

  const tenantId = encodeURIComponent(String(source.tenant_id || 'demo'));
  const channel = encodeURIComponent(String(source.channel || 'instagram'));
  const threadId = encodeURIComponent(String(source.thread_id || source.instagram_thread_id || ''));
  if (!threadId) return { text: '', rows: [], loaded: false, reason: 'missing_thread_id' };

  const url = baseRaw.replace(/\/$/, '') + '/conversation_events?select=role,content,created_at,intent,confidence&tenant_id=eq.' + tenantId + '&channel=eq.' + channel + '&instagram_thread_id=eq.' + threadId + '&order=created_at.desc&limit=16';
  try {
    const res = await fetch(url, {
      method: 'GET',
      headers: {
        apikey: key,
        Authorization: 'Bearer ' + key,
        Accept: 'application/json',
      },
    });
    if (!res.ok) return { text: '', rows: [], loaded: false, reason: 'history_http_' + res.status };
    const rows = await res.json();
    const ordered = Array.isArray(rows) ? rows.slice().reverse() : [];
    const text = ordered
      .map((row) => {
        const role = row.role === 'assistant' ? 'assistant' : row.role === 'system' ? 'system' : 'customer';
        return '[' + role + '] ' + String(row.content || '').replace(/\s+/g, ' ').trim();
      })
      .filter(Boolean)
      .join('\n');
    return { text, rows: ordered, loaded: true, reason: 'ok' };
  } catch (error) {
    return { text: '', rows: [], loaded: false, reason: 'history_error_' + String(error.message || error).slice(0, 80) };
  }
}

const threadHistoryResult = await loadRecentThreadHistory(source);
const threadHistoryText = threadHistoryResult.text
  ? 'Recent conversation memory from Supabase (oldest to newest):\n' + threadHistoryResult.text
  : 'Recent conversation memory from Supabase: none found for this tenant/channel/thread yet.';

const promptUser = 'Required response language:\n' + responseLanguage + '\n\nDefault/requested pricing currency:\n' + preferredCurrency + '\n\nPricing question detected:\n' + (askedPricing ? 'yes' : 'no') + '\n\nConversation starter detected:\n' + (conversationStarter ? 'yes' : 'no') + '\n\nLatest customer message:\n' + (messageText || '(empty)') + '\n\n' + threadHistoryText + '\n\nRetrieved/fallback context:\n' + retrievalContext;

return [{
  json: {
    ...source,
    message_text: messageText,
    retrieval_context: retrievalContext,
    prompt_system: promptSystem,
    prompt_user: promptUser,
    thread_history: threadHistoryResult.rows,
    thread_history_loaded: threadHistoryResult.loaded,
    thread_history_status: threadHistoryResult.reason,
    rag_confidence: retrievalSimilarity,
    confidence: retrievalSimilarity,
    similarity_threshold: minSimilarity,
    matched_document_ids: retrievedIds,
    matched_sources: retrievedSources,
    matched_languages: languages,
    sales_intent: commercialIntent,
    semantic_fallback_used: semanticFallbackUsed,
    sales_context_override: businessContextSignal,
    sales_fallback_used: semanticFallbackUsed,
    asked_pricing: askedPricing,
    preferred_currency: preferredCurrency,
    response_language: responseLanguage,
    conversation_starter: conversationStarter,
    escalation_decision_reason: decisionReason,
    escalate_by_confidence: escalateByConfidence,
  }
}];

const source = $json;
const responseLanguage = source.response_language || 'English';

function buildEscalationReply(language) {
  if (language === 'Russian') {
    return 'Передаю диалог человеку-оператору. Дальше я буду молчать в этом чате, пока оператор не сбросит маркер передачи.';
  }
  if (language === 'Vietnamese') {
    return 'Tôi sẽ chuyển cuộc trò chuyện này cho nhân viên phụ trách. Tôi sẽ giữ im lặng tại đây cho đến khi nhân viên đặt lại trạng thái chuyển tiếp.';
  }
  if (String(language || '').startsWith('Chinese')) {
    return '我会请人工客服查看并跟进。在操作员重置转接标记之前，我会在这里保持静默。';
  }
  return 'I will ask a human operator to review this and follow up. I will stay silent here until the operator resets the handoff marker.';
}

const reply = buildEscalationReply(responseLanguage);
return [{ json: { ...source, reply_text: reply, response_text: reply, response_language: responseLanguage } }];

